Future<ApiResult<void, Never>> deprecatedUnstableUpdateWebhooksParamWebhookId({required String webhookId, Object? body, }) async  { final headers = <String, String>{..._config.defaultHeaders};
headers['Content-Type'] = 'application/json';

final request = ApiRequest(
  method: 'PUT',
  path: '/admin/api/unstable/webhooks/${Uri.encodeComponent(webhookId)}.json',
  headers: headers,
  body: jsonEncode(body),
);

return _execute(
  request,
  onSuccess: (_) {},
);
 } 
